+    if (autonomousRoles.has(role)) {
+      await run("gt mail check --inject");
+    }
+    await run("gt nudge deacon session-started");
+  };
+
+  return {
+    event: async ({ event }) => {
+      if (event?.type === "session.created") {
+        await onSessionCreated();
+      }
